-- Privacy policy versions + profile consent + enforcement
-- Seed גרסה נוכחית (מסונכרן ל-git): 2026-04-04-v1

create table if not exists public.privacy_policies (
  id uuid primary key default gen_random_uuid(),
  version text not null unique,
  body text not null,
  updated_at timestamptz not null default now()
);

create index if not exists privacy_policies_updated_at_desc_idx
  on public.privacy_policies (updated_at desc);

alter table public.privacy_policies enable row level security;

drop policy if exists privacy_policies_select_public on public.privacy_policies;
create policy privacy_policies_select_public
  on public.privacy_policies for select
  to anon, authenticated
  using (true);

grant select on table public.privacy_policies to anon, authenticated;

create table if not exists public.profiles (
  id uuid primary key references auth.users(id) on delete cascade,
  full_name text,
  birthday date,
  phone text,
  updated_at timestamptz default now()
);

alter table public.profiles add column if not exists privacy_policy_version_accepted text;
alter table public.profiles add column if not exists privacy_policy_accepted_at timestamptz;

alter table public.profiles enable row level security;

drop policy if exists profiles_select_own on public.profiles;
create policy profiles_select_own
  on public.profiles for select
  to authenticated
  using (auth.uid() = id);

drop policy if exists profiles_insert_own on public.profiles;
create policy profiles_insert_own
  on public.profiles for insert
  to authenticated
  with check (auth.uid() = id);

drop policy if exists profiles_update_own on public.profiles;
create policy profiles_update_own
  on public.profiles for update
  to authenticated
  using (auth.uid() = id)
  with check (auth.uid() = id);

insert into public.privacy_policies (version, body, updated_at)
select '2026-04-04-v1', convert_from(decode('', 'base64'), 'UTF8')::text, '2026-04-04T12:00:00Z'::timestamptz
where not exists (select 1 from public.privacy_policies where version = '2026-04-04-v1');

create or replace function public.current_privacy_policy_version()
returns text
language sql
stable
security definer
set search_path = public
as $$
  select p.version
  from public.privacy_policies p
  order by p.updated_at desc, p.id desc
  limit 1;
$$;

create or replace function public.record_privacy_consent()
returns void
language plpgsql
security definer
set search_path = public
as $$
declare
  v_version text;
begin
  if auth.uid() is null then
    raise exception 'not_authenticated';
  end if;

  select public.current_privacy_policy_version() into v_version;
  if v_version is null then
    raise exception 'no_privacy_policy_configured';
  end if;

  insert into public.profiles (id, privacy_policy_version_accepted, privacy_policy_accepted_at, updated_at)
  values (auth.uid(), v_version, now(), now())
  on conflict (id) do update set
    privacy_policy_version_accepted = excluded.privacy_policy_version_accepted,
    privacy_policy_accepted_at = excluded.privacy_policy_accepted_at,
    updated_at = now();
end;
$$;

revoke all on function public.record_privacy_consent() from public;
grant execute on function public.record_privacy_consent() to authenticated;

revoke all on function public.current_privacy_policy_version() from public;
grant execute on function public.current_privacy_policy_version() to anon, authenticated;

create or replace function public.create_complete_order(
  p_order_id uuid,
  p_shipping_data jsonb,
  p_gift_data jsonb,
  p_items jsonb,
  p_subtotal numeric,
  p_total numeric
)
returns uuid
language plpgsql
security definer
set search_path = public
as $$
declare
  v_required text;
  v_accepted text;
begin
  if auth.uid() is null then
    raise exception 'not_authenticated';
  end if;

  select public.current_privacy_policy_version() into v_required;
  select p.privacy_policy_version_accepted into v_accepted
  from public.profiles p
  where p.id = auth.uid();

  if v_required is null then
    raise exception 'no_privacy_policy_configured';
  end if;
  if v_accepted is null or v_accepted <> v_required then
    raise exception 'privacy_policy_not_accepted';
  end if;

  insert into public.orders (
    id, user_id, status, currency, coupon_code, discount_amount,
    shipping_method, shipping_amount, subtotal_amount, total_amount,
    shipping_first_name, shipping_last_name, shipping_city, shipping_street,
    shipping_house_number, shipping_apartment_number, shipping_notes,
    gift_enabled, gift_message, gift_sender_name, gift_sender_phone
  ) values (
    p_order_id, auth.uid(), 'pending', 'ILS',
    nullif(p_shipping_data->>'couponCode', ''),
    0, 'home_delivery_free', 0, p_subtotal, p_total,
    p_shipping_data->>'firstName', p_shipping_data->>'lastName',
    p_shipping_data->>'city', p_shipping_data->>'street',
    (p_shipping_data->>'houseNum')::integer,
    nullif(p_shipping_data->>'aptNum', '')::integer,
    nullif(p_shipping_data->>'notes', ''),
    coalesce((p_gift_data->>'enabled')::boolean, false),
    nullif(p_gift_data->>'message', ''),
    nullif(p_gift_data->>'senderName', ''),
    nullif(p_gift_data->>'senderPhone', '')
  );

  insert into public.order_items (
    order_id, item_type, title, subtitle, unit_price, quantity, line_total, configuration
  )
  select p_order_id, i.type, i.title, i.subtitle, i.price,
    coalesce(i.quantity, 1), i.price * coalesce(i.quantity, 1), i.configuration
  from jsonb_to_recordset(p_items) as i(
    type text, title text, subtitle text, price numeric, quantity integer, configuration jsonb
  );

  return p_order_id;
end;
$$;

revoke all on function public.create_complete_order(uuid, jsonb, jsonb, jsonb, numeric, numeric) from public;
grant execute on function public.create_complete_order(uuid, jsonb, jsonb, jsonb, numeric, numeric) to authenticated;

create or replace function public.enforce_privacy_before_order_paid()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
declare
  v_required text;
  v_accepted text;
begin
  if new.status = 'paid' and (old.status is distinct from new.status) then
    select public.current_privacy_policy_version() into v_required;
    select p.privacy_policy_version_accepted into v_accepted
    from public.profiles p where p.id = new.user_id;
    if v_required is null then
      raise exception 'no_privacy_policy_configured';
    end if;
    if v_accepted is null or v_accepted <> v_required then
      raise exception 'privacy_policy_not_accepted';
    end if;
  end if;
  return new;
end;
$$;

drop trigger if exists orders_enforce_privacy_paid on public.orders;
create trigger orders_enforce_privacy_paid
  before update of status on public.orders
  for each row
  execute function public.enforce_privacy_before_order_paid();
